CREATE OR REPLACE FUNCTION public.aplicar_ajuste_estacional(p_departamento_codigo text, p_fecha_inicio date, p_dias_duracion integer, p_costo_base numeric)
 RETURNS TABLE(costo_base numeric, factor_estacional_promedio numeric, costo_ajustado numeric, diferencia_costo numeric, porcentaje_ajuste numeric, condiciones_especiales text[])
 LANGUAGE plpgsql
 SET search_path TO 'public'
AS $function$
DECLARE
  v_fecha_actual date := p_fecha_inicio;
  v_fecha_fin date := p_fecha_inicio + (p_dias_duracion || ' days')::interval;
  v_factor_total numeric := 0;
  v_factor_count integer := 0;
  v_factor_estacional numeric;
  v_factor_promedio numeric;
  v_costo_ajustado numeric;
  v_condiciones text[] := '{}';
  v_registro RECORD;
BEGIN
  -- Calcular promedio de factores estacionales durante el período
  WHILE v_fecha_actual <= v_fecha_fin LOOP
    SELECT * INTO v_registro FROM obtener_factor_estacional(p_departamento_codigo, EXTRACT(MONTH FROM v_fecha_actual)::integer);
    
    IF FOUND THEN
      v_factor_total := v_factor_total + (v_registro.factor_costo * v_registro.factor_productividad);
      v_factor_count := v_factor_count + 1;
      
      IF v_registro.condiciones_especiales IS NOT NULL THEN
        v_condiciones := array_append(v_condiciones, v_registro.condiciones_especiales);
      END IF;
    END IF;
    
    v_fecha_actual := v_fecha_actual + INTERVAL '1 day';
  END LOOP;
  
  -- Calcular factor promedio
  IF v_factor_count > 0 THEN
    v_factor_promedio := v_factor_total / v_factor_count;
  ELSE
    v_factor_promedio := 1.0; -- Sin datos, usar factor neutro
  END IF;
  
  -- Aplicar factor al costo base
  v_costo_ajustado := p_costo_base * v_factor_promedio;
  
  RETURN QUERY
  SELECT
    p_costo_base as costo_base,
    v_factor_promedio as factor_estacional_promedio,
    v_costo_ajustado as costo_ajustado,
    (v_costo_ajustado - p_costo_base) as diferencia_costo,
    ((v_costo_ajustado - p_costo_base) / p_costo_base * 100) as porcentaje_ajuste,
    v_condiciones as condiciones_especiales;
END;
$function$

CREATE OR REPLACE FUNCTION public.aplicar_factores_escala(p_tipo_proyecto text, p_presupuesto_base numeric, p_costo_directo numeric)
 RETURNS TABLE(presupuesto_base numeric, costo_ajustado numeric, factor_economia_aplicado numeric, factor_administracion_aplicado numeric, factor_imprevistos_aplicado numeric, factor_total numeric, presupuesto_final numeric, escala_identificada text)
 LANGUAGE plpgsql
 SET search_path TO 'public'
AS $function$
DECLARE
  v_escala RECORD;
  v_factor_total numeric;
  v_costo_ajustado numeric;
  v_presupuesto_final numeric;
BEGIN
  -- Obtener escala de producción
  SELECT * INTO v_escala FROM obtener_escala_produccion(p_tipo_proyecto, p_presupuesto_base);
  
  IF NOT FOUND THEN
    -- Si no se encuentra escala, usar valores por defecto (mediano)
    v_escala.factor_economia := 1.10;
    v_escala.factor_administracion := 1.12;
    v_escala.factor_imprevistos := 1.08;
    v_escala.rango_tamano := 'desconocido';
  END IF;
  
  -- Calcular factor total
  v_factor_total := v_escala.factor_economia * v_escala.factor_administracion * v_escala.factor_imprevistos;
  
  -- Aplicar factores al costo directo
  v_costo_ajustado := p_costo_directo * v_escala.factor_economia;
  v_presupuesto_final := v_costo_ajustado * v_escala.factor_administracion * v_escala.factor_imprevistos;
  
  RETURN QUERY
  SELECT
    p_presupuesto_base as presupuesto_base,
    v_costo_ajustado as costo_ajustado,
    v_escala.factor_economia as factor_economia_aplicado,
    v_escala.factor_administracion as factor_administracion_aplicado,
    v_escala.factor_imprevistos as factor_imprevistos_aplicado,
    v_factor_total as factor_total,
    v_presupuesto_final as presupuesto_final,
    v_escala.rango_tamano as escala_identificada;
END;
$function$

CREATE OR REPLACE FUNCTION public.assign_user_role(user_email text, new_rol text)
 RETURNS boolean
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  user_id uuid;
BEGIN
  -- Validar que el rol sea válido
  IF new_rol NOT IN ('Administrador', 'Gerente', 'Residente', 'Compras', 'Bodeguero', 'usuario') THEN
    RAISE EXCEPTION 'Rol inválido: %', new_rol;
    RETURN false;
  END IF;

  -- Buscar usuario por email
  SELECT id INTO user_id
  FROM auth.users
  WHERE email = user_email
  LIMIT 1;

  IF user_id IS NULL THEN
    RAISE EXCEPTION 'Usuario no encontrado: %', user_email;
    RETURN false;
  END IF;

  -- Actualizar o crear perfil con el nuevo rol
  INSERT INTO public.profiles (id, nombre, rol, user_metadata)
  VALUES (
    user_id,
    COALESCE(
      (SELECT nombre FROM public.profiles WHERE id = user_id),
      split_part(user_email, '@', 1)
    ),
    new_rol,
    jsonb_build_object('email', user_email)
  )
  ON CONFLICT (id) DO UPDATE SET
    rol = new_rol,
    updated_at = now();

  RETURN true;
END;
$function$

CREATE OR REPLACE FUNCTION public.audit_trigger_func()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  IF (TG_OP = 'DELETE') THEN
    INSERT INTO erp_audit_log (table_name, record_id, action, old_data, changed_by)
    VALUES (TG_TABLE_NAME, OLD.id, 'DELETE', row_to_json(OLD), auth.uid());
    RETURN OLD;
  ELSIF (TG_OP = 'UPDATE') THEN
    INSERT INTO erp_audit_log (table_name, record_id, action, old_data, new_data, changed_by, changed_fields)
    VALUES (
      TG_TABLE_NAME,
      NEW.id,
      'UPDATE',
      row_to_json(OLD),
      row_to_json(NEW),
      auth.uid(),
      NULL
    );
    RETURN NEW;
  ELSIF (TG_OP = 'INSERT') THEN
    INSERT INTO erp_audit_log (table_name, record_id, action, new_data, changed_by)
    VALUES (TG_TABLE_NAME, NEW.id, 'INSERT', row_to_json(NEW), auth.uid());
    RETURN NEW;
  END IF;
  RETURN NULL;
END;
$function$

CREATE OR REPLACE FUNCTION public.calcular_dosificacion(p_resistencia text, p_tipo text, "p_tamaño_agregado" text, p_aditivos text, p_curado text, p_volumen numeric, p_departamento text DEFAULT NULL::text, p_altitud numeric DEFAULT NULL::numeric)
 RETURNS TABLE(cemento_sacos numeric, arena_m3 numeric, piedra_m3 numeric, agua_lt numeric, factor_ajuste numeric, costo_total numeric)
 LANGUAGE plpgsql
 SET search_path TO 'public'
AS $function$
DECLARE
  v_dosificacion RECORD;
  v_factor_altitud numeric := 1.0;
  v_factor_temperatura numeric := 1.0;
  v_factor_curado numeric := 1.0;
  v_precio_cemento numeric := 92;
  v_precio_arena numeric := 145;
  v_precio_piedra numeric := 195;
BEGIN
  SELECT * INTO v_dosificacion
  FROM erp_dosificaciones_concreto
  WHERE resistencia = p_resistencia
    AND tipo = p_tipo
    AND tamaño_agregado = p_tamaño_agregado
    AND aditivos = p_aditivos
    AND curado = p_curado
    AND activo = true
  LIMIT 1;

  IF p_altitud IS NOT NULL THEN
    IF p_altitud > 2000 THEN
      v_factor_altitud := 1.05;
    ELSIF p_altitud > 1000 AND p_altitud <= 2000 THEN
      v_factor_altitud := 1.0;
    ELSE
      v_factor_altitud := 0.98;
    END IF;
  END IF;

  IF p_departamento IS NOT NULL THEN
    CASE p_departamento
      WHEN 'GT-01' THEN v_factor_temperatura := 1.0;
      WHEN 'GT-02' THEN v_factor_temperatura := 0.95;
      WHEN 'GT-03' THEN v_factor_temperatura := 0.95;
      WHEN 'GT-08' THEN v_factor_temperatura := 1.4;
      WHEN 'GT-12' THEN v_factor_temperatura := 1.5;
      WHEN 'GT-15' THEN v_factor_temperatura := 1.2;
      ELSE v_factor_temperatura := 1.0;
    END CASE;
  END IF;

  IF p_curado = 'acelerado' THEN
    v_factor_curado := 1.2;
  ELSIF p_curado = 'prolongado' THEN
    v_factor_curado := 1.3;
  ELSE
    v_factor_curado := 1.0;
  END IF;

  RETURN QUERY
  SELECT
    v_dosificacion.cemento_sacos_m3 * p_volumen * v_factor_altitud * v_factor_curado AS cemento_sacos,
    v_dosificacion.arena_m3_m3 * p_volumen * v_factor_altitud AS arena_m3,
    v_dosificacion.piedra_m3_m3 * p_volumen * v_factor_altitud AS piedra_m3,
    v_dosificacion.agua_lt_m3 * p_volumen * v_factor_temperatura AS agua_lt,
    v_factor_altitud * v_factor_temperatura * v_factor_curado AS factor_ajuste,
    (v_dosificacion.cemento_sacos_m3 * v_precio_cemento +
     v_dosificacion.arena_m3_m3 * v_precio_arena +
     v_dosificacion.piedra_m3_m3 * v_precio_piedra) * p_volumen * v_factor_altitud * v_factor_temperatura * v_factor_curado AS costo_total;
END;
$function$

CREATE OR REPLACE FUNCTION public.calcular_movimiento_tierra(p_tipo text, p_suelo text, p_profundidad text, p_acceso text, p_drenaje text, p_volumen numeric)
 RETURNS TABLE(costo_unitario numeric, costo_total numeric, tiempo_estimado_dias numeric, equipo_requerido text[], factor_ajuste_total numeric)
 LANGUAGE plpgsql
 SET search_path TO 'public'
AS $function$
DECLARE
  v_parametros RECORD;
  v_factor_total numeric;
  v_costo_unitario numeric;
  v_tiempo_dias numeric;
BEGIN
  -- Obtener parámetros base
  SELECT * INTO v_parametros
  FROM erp_parametros_movimiento_tierra
  WHERE tipo = p_tipo
    AND suelo = p_suelo
    AND profundidad = p_profundidad
    AND acceso = p_acceso
    AND drenaje = p_drenaje
    AND activo = true
  LIMIT 1;

  IF NOT FOUND THEN
    -- Si no se encuentra combinación exacta, usar valores por defecto
    v_parametros.costo_base_m3 := 80;
    v_parametros.rendimiento_diario_m3 := 40;
    v_parametros.factor_profundidad := 1.0;
    v_parametros.factor_acceso := 1.0;
    v_parametros.factor_drenaje := 1.0;
    v_parametros.equipo_requerido := ARRAY['Retroexcavadora', 'Camión volquete'];
  END IF;

  -- Calcular factor total de ajuste
  v_factor_total := v_parametros.factor_profundidad * v_parametros.factor_acceso * v_parametros.factor_drenaje;
  
  -- Calcular costo unitario ajustado
  v_costo_unitario := v_parametros.costo_base_m3 * v_factor_total;
  
  -- Calcular tiempo estimado en días
  v_tiempo_dias := CEIL(p_volumen / v_parametros.rendimiento_diario_m3);
  
  -- Retornar resultados
  RETURN QUERY
  SELECT
    v_costo_unitario as costo_unitario,
    v_costo_unitario * p_volumen as costo_total,
    v_tiempo_dias as tiempo_estimado_dias,
    v_parametros.equipo_requerido as equipo_requerido,
    v_factor_total as factor_ajuste_total;
END;
$function$

CREATE OR REPLACE FUNCTION public.calcular_muro_contencion(p_altura_m numeric, p_tipo text, p_tipo_cimentacion text, p_tipo_suelo text, p_tipo_drenaje text, p_longitud_m numeric)
 RETURNS TABLE(costo_unitario_m2 numeric, costo_total numeric, factor_ajuste_total numeric, volumen_concreto_m3 numeric, referencia_norma text)
 LANGUAGE plpgsql
 SET search_path TO 'public'
AS $function$
DECLARE
  v_parametros RECORD;
  v_factor_total numeric;
  v_costo_unitario numeric;
  v_costo_total numeric;
  v_volumen_concreto numeric;
BEGIN
  SELECT * INTO v_parametros
  FROM erp_parametros_muros_contencion
  WHERE altura_m = p_altura_m
    AND tipo = p_tipo
    AND tipo_cimentacion = p_tipo_cimentacion
    AND tipo_suelo = p_tipo_suelo
    AND tipo_drenaje = p_tipo_drenaje
    AND activo = true
  LIMIT 1;

  IF NOT FOUND THEN
    v_parametros.costo_base_m2 := 500;
    v_parametros.factor_profundidad := 1.5;
    v_parametros.factor_suelo := 1.1;
    v_parametros.factor_drenaje := 1.0;
    v_parametros.referencia_norma := 'AGIES 62.01 (default)';
  END IF;

  v_factor_total := v_parametros.factor_profundidad * v_parametros.factor_suelo * v_parametros.factor_drenaje;
  v_costo_unitario := v_parametros.costo_base_m2 * v_factor_total;
  v_costo_total := v_costo_unitario * (p_altura_m * p_longitud_m);
  v_volumen_concreto := (p_altura_m * p_longitud_m) * 0.3;
  
  RETURN QUERY
  SELECT
    v_costo_unitario as costo_unitario_m2,
    v_costo_total as costo_total,
    v_factor_total as factor_ajuste_total,
    v_volumen_concreto as volumen_concreto_m3,
    v_parametros.referencia_norma as referencia_norma;
END;
$function$

CREATE OR REPLACE FUNCTION public.calcular_pavimento(p_uso text, p_tipo text, p_tipo_base text, p_tipo_sello text, p_area_m2 numeric)
 RETURNS TABLE(espesor_cm numeric, costo_superficie_m2 numeric, costo_base_m3 numeric, costo_sello_m2 numeric, costo_total_m2 numeric, costo_total numeric, volumen_base_m3 numeric, referencia_norma text)
 LANGUAGE plpgsql
 SET search_path TO 'public'
AS $function$
DECLARE
  v_parametros RECORD;
  v_costo_total_m2 numeric;
  v_costo_total numeric;
  v_volumen_base_m3 numeric;
BEGIN
  SELECT * INTO v_parametros
  FROM erp_parametros_pavimentos
  WHERE uso = p_uso
    AND tipo = p_tipo
    AND tipo_base = p_tipo_base
    AND tipo_sello = p_tipo_sello
    AND activo = true
  LIMIT 1;

  IF NOT FOUND THEN
    v_parametros.espesor_minimo_cm := 10;
    v_parametros.costo_base_m2 := 150;
    v_parametros.costo_base_m3 := 160;
    v_parametros.costo_sello_m2 := 15;
    v_parametros.referencia_norma := 'AGIES 51.02 (default)';
  END IF;

  v_costo_total_m2 := v_parametros.costo_base_m2 + v_parametros.costo_sello_m2;
  v_costo_total := v_costo_total_m2 * p_area_m2;
  v_volumen_base_m3 := (v_parametros.espesor_minimo_cm / 100) * p_area_m2;
  
  RETURN QUERY
  SELECT
    v_parametros.espesor_minimo_cm as espesor_cm,
    v_parametros.costo_base_m2 as costo_superficie_m2,
    v_parametros.costo_base_m3 as costo_base_m3,
    v_parametros.costo_sello_m2 as costo_sello_m2,
    v_costo_total_m2 as costo_total_m2,
    v_costo_total as costo_total,
    v_volumen_base_m3 as volumen_base_m3,
    v_parametros.referencia_norma as referencia_norma;
END;
$function$

CREATE OR REPLACE FUNCTION public.calcular_red_infraestructura(p_tipo text, p_diametro_pulgadas numeric, p_material text, p_presion text, p_longitud_ml numeric)
 RETURNS TABLE(costo_unitario_ml numeric, costo_total numeric, factor_ajuste_material numeric, referencia_norma text)
 LANGUAGE plpgsql
 SET search_path TO 'public'
AS $function$
DECLARE
  v_parametros RECORD;
  v_costo_unitario numeric;
  v_costo_total numeric;
BEGIN
  SELECT * INTO v_parametros
  FROM erp_parametros_redes_infraestructura
  WHERE tipo = p_tipo
    AND diametro_pulgadas = p_diametro_pulgadas
    AND material = p_material
    AND presion = p_presion
    AND activo = true
  LIMIT 1;

  IF NOT FOUND THEN
    v_parametros.costo_base_ml := 100;
    v_parametros.factor_material := 1.0;
    v_parametros.referencia_norma := 'COGUANOR NGO 41001 (default)';
  END IF;

  v_costo_unitario := v_parametros.costo_base_ml * v_parametros.factor_material;
  v_costo_total := v_costo_unitario * p_longitud_ml;
  
  RETURN QUERY
  SELECT
    v_costo_unitario as costo_unitario_ml,
    v_costo_total as costo_total,
    v_parametros.factor_material as factor_ajuste_material,
    v_parametros.referencia_norma as referencia_norma;
END;
$function$

CREATE OR REPLACE FUNCTION public.cleanup_old_error_logs(days_to_keep integer DEFAULT 90)
 RETURNS integer
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_deleted_count INTEGER;
BEGIN
  DELETE FROM erp_error_log
  WHERE created_at < NOW() - (days_to_keep || ' days')::INTERVAL
  AND resolved = TRUE;

  GET DIAGNOSTICS v_deleted_count = ROW_COUNT;

  RETURN v_deleted_count;
END;
$function$

CREATE OR REPLACE FUNCTION public.descontar_stock_vale(p_items jsonb, p_vale_id uuid DEFAULT NULL::uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_item JSONB;
  v_material_id UUID;
  v_cantidad NUMERIC;
  v_stock_actual NUMERIC;
  v_result JSONB;
BEGIN
  FOR v_item IN SELECT * FROM jsonb_array_elements(p_items)
  LOOP
    v_material_id := (v_item->>'materialId')::UUID;
    v_cantidad := (v_item->>'cantidad')::NUMERIC;
    IF v_material_id IS NULL OR v_cantidad IS NULL THEN
      RAISE EXCEPTION 'Item inválido: materialId o cantidad faltante';
    END IF;
    SELECT stock INTO v_stock_actual FROM erp_materiales WHERE id = v_material_id FOR UPDATE;
    IF NOT FOUND THEN RAISE EXCEPTION 'Material no encontrado: %', v_material_id; END IF;
    IF v_stock_actual < v_cantidad THEN
      RAISE EXCEPTION 'Stock insuficiente para material %: disponible %, requerido %', v_material_id, v_stock_actual, v_cantidad;
    END IF;
    UPDATE erp_materiales SET stock = stock - v_cantidad, updated_at = now() WHERE id = v_material_id;
  END LOOP;
  v_result := jsonb_build_object('success', true, 'message', 'Stock descontado exitosamente');
  IF p_vale_id IS NOT NULL THEN v_result := v_result || jsonb_build_object('valeId', p_vale_id); END IF;
  RETURN v_result;
EXCEPTION WHEN OTHERS THEN
  RETURN jsonb_build_object('success', false, 'error', SQLERRM, 'detail', COALESCE(SQLSTATE, ''));
END;
$function$

