CREATE OR REPLACE FUNCTION public.rls_auto_enable()
 RETURNS event_trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  cmd record;
BEGIN
  FOR cmd IN
    SELECT *
    FROM pg_event_trigger_ddl_commands()
    WHERE command_tag IN ('CREATE TABLE', 'CREATE TABLE AS', 'SELECT INTO')
      AND object_type IN ('table','partitioned table')
  LOOP
     IF cmd.schema_name IS NOT NULL AND cmd.schema_name IN ('public') AND cmd.schema_name NOT IN ('pg_catalog','information_schema') AND cmd.schema_name NOT LIKE 'pg_toast%' AND cmd.schema_name NOT LIKE 'pg_temp%' THEN
      BEGIN
        EXECUTE format('alter table if exists %s enable row level security', cmd.object_identity);
        RAISE LOG 'rls_auto_enable: enabled RLS on %', cmd.object_identity;
      EXCEPTION
        WHEN OTHERS THEN
          RAISE LOG 'rls_auto_enable: failed to enable RLS on %', cmd.object_identity;
      END;
     ELSE
        RAISE LOG 'rls_auto_enable: skip % (either system schema or not in enforced list: %.)', cmd.object_identity, cmd.schema_name;
     END IF;
  END LOOP;
END;
$function$

CREATE OR REPLACE FUNCTION public.rollback_054_monitoring_functions()
 RETURNS void
 LANGUAGE plpgsql
 SET search_path TO 'public'
AS $function$
BEGIN
  -- Revoke permissions
  REVOKE EXECUTE ON FUNCTION get_table_sizes() FROM authenticated;
  REVOKE EXECUTE ON FUNCTION get_slow_queries() FROM authenticated;
  REVOKE EXECUTE ON FUNCTION get_index_usage() FROM authenticated;
  REVOKE EXECUTE ON FUNCTION get_missing_indexes() FROM authenticated;
  
  -- Drop functions
  DROP FUNCTION IF EXISTS get_table_sizes();
  DROP FUNCTION IF EXISTS get_slow_queries();
  DROP FUNCTION IF EXISTS get_index_usage();
  DROP FUNCTION IF EXISTS get_missing_indexes();
  
  RAISE NOTICE 'Migration 054 rolled back successfully';
END;
$function$

CREATE OR REPLACE FUNCTION public.rollback_056_deadlock_prevention()
 RETURNS void
 LANGUAGE plpgsql
 SET search_path TO 'public'
AS $function$
BEGIN
  DROP FUNCTION IF EXISTS begin_transaction(TEXT);
  DROP FUNCTION IF EXISTS commit_transaction();
  DROP FUNCTION IF EXISTS rollback_transaction();
  DROP FUNCTION IF EXISTS try_advisory_lock(BIGINT, INTEGER);
  DROP FUNCTION IF EXISTS release_advisory_lock(BIGINT);
  DROP FUNCTION IF EXISTS log_deadlock_event(TEXT, TEXT, TEXT, TEXT);
END;
$function$

CREATE OR REPLACE FUNCTION public.try_advisory_lock(lock_id bigint, timeout_ms integer DEFAULT 5000)
 RETURNS boolean
 LANGUAGE plpgsql
 SET search_path TO 'public'
AS $function$
DECLARE
  start_time TIMESTAMP := NOW();
  locked BOOLEAN;
BEGIN
  WHILE (NOW() - start_time) * 1000 < timeout_ms LOOP
    locked := pg_try_advisory_xact_lock(lock_id);
    IF locked THEN
      RETURN TRUE;
    END IF;
    PERFORM pg_sleep(0.1);
  END LOOP;
  RETURN FALSE;
END;
$function$

